challenges.test_code:
config = parse_config('host=localhost\nport=8080')
assert config == {'host': 'localhost', 'port': '8080'}
config2 = parse_config('# Database config\ndb_host = 127.0.0.1\ndb_port = 5432\n\n# End')
assert config2 == {'db_host': '127.0.0.1', 'db_port': '5432'}
assert parse_config('') == {}
assert parse_config('# comment only') == {}
assert parse_config('\n\n\n') == {}
config3 = parse_config('key = value with = equals')
assert config3 == {'key': 'value with = equals'}
config4 = parse_config('  spaced_key  =  spaced_value  ')
assert config4 == {'spaced_key': 'spaced_value'}
config5 = parse_config('valid=yes\ninvalid_line\nalso_valid=true')
assert config5 == {'valid': 'yes', 'also_valid': 'true'}
